import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
} from 'chart.js';
import { Bar, Pie, Line } from 'react-chartjs-2';
import {
  UsersIcon,
  DocumentTextIcon,
  MapPinIcon,
  ExclamationTriangleIcon,
  ArrowTrendingUpIcon,
  CheckCircleIcon,
  UserIcon,
  ArrowRightOnRectangleIcon,
  CpuChipIcon,
  ChartBarIcon,
  SparklesIcon,
  ClockIcon,
  BellIcon,
  ArrowPathIcon
} from '@heroicons/react/24/outline';
import MLPredictionTab from '../components/admin/MLPredictionTab';
import ComplaintManagement from '../components/admin/ComplaintManagement';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
);

const AdminDashboard = () => {
  const [user, setUser] = useState(null);
  const [selectedTimeRange, setSelectedTimeRange] = useState('7d');
  const [activeTab, setActiveTab] = useState('overview');
  const [mlData, setMlData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [lastUpdate, setLastUpdate] = useState(new Date());
  const navigate = useNavigate();

  // Modern Glass Card Component
  const GlassCard = ({ children, className = "" }) => (
    <div className={`bg-white/80 backdrop-blur-xl border border-white/60 shadow-lg rounded-2xl transition-all duration-300 hover:shadow-xl hover:shadow-blue-100/50 overflow-hidden relative ${className}`}>
      {children}
    </div>
  );

  // Fetch ML data
  const fetchMLData = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/ml/prediction/overview', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const data = await response.json();
      setMlData(data);
      setLastUpdate(new Date());
    } catch (error) {
      console.error('Error fetching ML data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // Check if user is logged in and is admin
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    const user = JSON.parse(userData);
    if (user.userType !== 'admin') {
      navigate('/dashboard'); // Redirect non-admin users
      return;
    }

    setUser(user);
    fetchMLData(); // Fetch ML data on component mount

    // Set up auto-refresh for ML data
    const interval = setInterval(fetchMLData, 30000); // Refresh every 30 seconds
    return () => clearInterval(interval);
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  // Sample data for charts
  const complaintsByCategory = {
    labels: ['Infrastructure', 'Sanitation', 'Water Supply', 'Roads', 'Public Safety', 'Electricity'],
    datasets: [
      {
        label: 'Number of Complaints',
        data: [45, 38, 32, 28, 25, 20],
        backgroundColor: [
          'rgba(99, 102, 241, 0.9)',  // Indigo
          'rgba(34, 197, 94, 0.9)',   // Green
          'rgba(59, 130, 246, 0.9)',  // Blue
          'rgba(251, 146, 60, 0.9)',  // Orange
          'rgba(168, 85, 247, 0.9)',  // Purple
          'rgba(236, 72, 153, 0.9)'   // Pink
        ],
        borderColor: [
          'rgba(99, 102, 241, 1)',
          'rgba(34, 197, 94, 1)',
          'rgba(59, 130, 246, 1)',
          'rgba(251, 146, 60, 1)',
          'rgba(168, 85, 247, 1)',
          'rgba(236, 72, 153, 1)'
        ],
        borderWidth: 2,
        borderRadius: 8,
        borderSkipped: false,
      },
    ],
  };

  const complaintsByStatus = {
    labels: ['Pending', 'In Progress', 'Resolved', 'Rejected'],
    datasets: [
      {
        data: [30, 45, 120, 5],
        backgroundColor: [
          'rgba(251, 191, 36, 0.8)',
          'rgba(59, 130, 246, 0.8)',
          'rgba(34, 197, 94, 0.8)',
          'rgba(239, 68, 68, 0.8)'
        ],
        borderColor: [
          'rgba(251, 191, 36, 1)',
          'rgba(59, 130, 246, 1)',
          'rgba(34, 197, 94, 1)',
          'rgba(239, 68, 68, 1)'
        ],
        borderWidth: 1,
      },
    ],
  };

  const weeklyTrends = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Complaints Received',
