                </h3>
                <div className="bg-white rounded-xl p-4">
                  <Bar data={complaintsByCategory} options={barChartOptions} />
                </div>
              </div>

              {/* Complaints by Status */}
              <div className="bg-gradient-to-br from-white to-gray-50 p-6 shadow-xl rounded-2xl border border-gray-100 hover:shadow-2xl transition-shadow duration-300">
