                  <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                    <div className="p-2 bg-red-100 rounded-lg mr-3">
                      <MapPinIcon className="h-5 w-5 text-red-600" />
                    </div>
                    Hotspot Areas
                  </h3>
                  <div className="overflow-hidden">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead>
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Area
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Complaints
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Severity
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Trend
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {hotspots.map((hotspot) => (
                          <tr key={hotspot.id} className="hover:bg-gray-50 transition-colors">
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                              {hotspot.area}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {hotspot.complaints}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className={getSeverityBadge(hotspot.severity)}>
                                {hotspot.severity}
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {getTrendIcon(hotspot.trend)}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>

              {/* Recent Activity */}
              <div className="bg-gradient-to-br from-white to-gray-50 shadow-xl rounded-2xl border border-gray-100 hover:shadow-2xl transition-shadow duration-300">
                <div className="px-6 py-5 sm:p-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                    <div className="p-2 bg-purple-100 rounded-lg mr-3">
                      <ArrowTrendingUpIcon className="h-5 w-5 text-purple-600" />
                    </div>
                    Recent Activity
                  </h3>
                  <div className="flow-root">
                    <ul className="-mb-8">
                      {recentActivity.map((activity, index) => (
                        <li key={activity.id}>
                          <div className="relative pb-8">
                            {index !== recentActivity.length - 1 && (
                              <span
                                className="absolute top-4 left-4 -ml-px h-full w-0.5 bg-gray-200"
                                aria-hidden="true"
                              />
                            )}
                            <div className="relative flex space-x-3">
                              <div>
                                <span className={`h-8 w-8 rounded-full flex items-center justify-center ring-8 ring-white ${activity.type === 'complaint' ? 'bg-blue-500' :
                                    activity.type === 'hotspot' ? 'bg-red-500' :
                                      activity.type === 'resolved' ? 'bg-green-500' :
                                        activity.type === 'critical' ? 'bg-orange-500' :
                                          'bg-purple-500'
                                  }`}>
                                  <span className="text-white text-xs font-medium">
                                    {activity.type === 'complaint' ? 'C' :
                                      activity.type === 'hotspot' ? 'H' :
                                        activity.type === 'resolved' ? 'R' :
                                          activity.type === 'critical' ? '!' :
                                            'U'}
                                  </span>
                                </span>
                              </div>
                              <div className="min-w-0 flex-1 pt-1.5 flex justify-between space-x-4">
                                <div>
                                  <p className="text-sm text-gray-900">{activity.action}</p>
                                  <p className="text-sm text-gray-500">
                                    {activity.user || activity.area || activity.severity}
                                  </p>
                                </div>
                                <div className="text-right text-sm whitespace-nowrap text-gray-500">
                                  <time dateTime={activity.time}>{activity.time}</time>
                                </div>
                              </div>
                            </div>
                          </div>
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
